{
  "business_expectations": [
    {
      "expectation_id": "轻症多次赔付确认",
      "description": "回答应明确说明轻症通常可以多次赔付，回应用户关于赔付次数的直接疑问。",
      "acceptance_criteria": "Actual answer 中包含“轻症可以多次赔付”或语义等同的陈述。",
      "blocking_level": "blocking"
    },
    {
      "expectation_id": "轻症赔付比例说明",
      "description": "回答应提供每次轻症赔付占基本保额的比例范围，回应用户“每次赔多少”的核心问题。",
      "acceptance_criteria": "明确给出赔付比例，如20%至30%，并关联基本保险金额。",
      "blocking_level": "blocking"
    },
    {
      "expectation_id": "赔付次数上限与间隔期提示",
      "description": "回答应提示轻症多次赔付存在次数上限和间隔期要求，帮助用户理解多次赔付的限制。",
      "acceptance_criteria": "提及“次数上限”（如3次或5次）和“间隔期”概念。",
      "blocking_level": "non-blocking"
    },
    {
      "expectation_id": "引导查阅具体合同",
      "description": "回答应建议用户查阅其保险合同条款以获取准确信息，因为具体规则以合同为准。",
      "acceptance_criteria": "包含类似“建议查阅保险合同”或“以合同条款为准”的指引。",
      "blocking_level": "blocking"
    }
  ],
  "fulfillment_assessments": [
    {
      "expectation_id": "轻症多次赔付确认",
      "status": "fulfilled",
      "actual_evidence": "一般情况下，轻症可以赔付多次。",
      "assessment_reasoning": "明确肯定轻症可多次赔付，完全满足用户对次数问题的期待。"
    },
    {
      "expectation_id": "轻症赔付比例说明",
      "status": "fulfilled",
      "actual_evidence": "每次赔付金额通常为基本保险金额的20%至30%。",
      "assessment_reasoning": "清楚给出了比例范围和金额基准，直接解答了“每次赔多少”。"
    },
    {
      "expectation_id": "赔付次数上限与间隔期提示",
      "status": "fulfilled",
      "actual_evidence": "可能有次数上限（如3次或5次）和间隔期要求。",
      "assessment_reasoning": "虽然未提供间隔期具体时长，但已明确提示存在上限和间隔期，为用户提供了必要的风险认知信息。"
    },
    {
      "expectation_id": "引导查阅具体合同",
      "status": "fulfilled",
      "actual_evidence": "建议查阅您的保险合同条款获取准确信息。",
      "assessment_reasoning": "末尾给出了清晰的行动指引，强调合同为准，满足引导需求。"
    }
  ],
  "overall_fulfillment": {
    "status": "fulfilled",
    "why": "所有核心业务期望均已满足：回答了能否多次赔付、赔付比例，并提示了限制和查阅合同，信息准确且有用。"
  },
  "expected": {
    "type": "gold_answer",
    "content": "通常情况下，您购买的重疾险合同中关于轻症责任的赔付规则如下：1. 轻症可以多次赔付，具体次数以合同约定为准（常见为3-5次）。每次确诊的轻症需满足合同定义的疾病标准，且两次轻症确诊之间通常有间隔期（如90天或180天）。2. 每次轻症赔付的金额一般为基本保额的一定比例，常见比例为20%-30%。例如保额50万，每次轻症可赔付10万-15万。部分产品轻症赔付后重疾保额不变，部分产品会相应减少。3. 需要注意，轻症责任可能设有分组限制，即同一组别的轻症只能赔付一次；另外，轻症赔付后合同继续有效，但累计赔付上限可能有限制。以上为一般规则，具体赔付条件、次数、金额比例请以您持有的保险合同条款为准。建议您查阅合同中的“保险责任”及“轻症疾病保险金”章节，或直接咨询保险公司客服获取准确信息。"
  },
  "intent_model": {
    "primary_question": "轻症是否能够多次赔付？",
    "secondary_question": "每次轻症赔付的具体金额是多少？",
    "domain": "重疾险理赔",
    "expected_answer_type": "基于合同条款的一般性解释，同时提示以具体合同为准"
  },
  "consumer_contract": {
    "required_output_elements": [
