      "提示次数上限和间隔期",
      "建议查阅合同"
    ],
    "optional_elements": [
      "间隔期具体时长",
      "分组限制说明",
      "赔付后保额变化说明"
    ]
  },
  "reconstructed_intent": "用户投保了重疾险，想了解合同下轻症责任：轻症是赔多次还是一次？每次赔多少？期望得到明确的通用规则，并被告知需以合同为准。",
  "judge_basis": "以用户问题为基准，参照标准答案（gold answer）核实实际回答的核心信息覆盖度和准确性，依据qa_gold_answer场景标准。",
  "judge_method": "基于关键意图维度的拆分评估：将用户意图分解为多次赔付确认、赔付比例、次数/间隔期提示、合同引导四个原子期望，逐一对照实际输出判定满足状态。",
  "semantic_equivalence_checks": [],
  "reference_generation_basis": {
    "source": "gold_answer",
    "description": "提供了详细的通用规则，涵盖多次赔付、比例、间隔期、分组、保额影响等，并提醒以合同为准。"
  },
  "verdict_derivation": {
    "score_dimensions": {
      "correctness": 1.0,
      "completeness": 0.9,
      "clarity": 0.95,
      "key_point_coverage": 0.85
    }
  },
  "boundary_decision": {
    "within_evaluable_scope": true,
    "uncontrollable_limits": [],
    "evaluable_errors": []
  },
  "evaluation_boundary": {
    "scenario": "qa_gold_answer",
    "description": "评估基于实际输出与gold answer的对比，重点考察核心问题的回答准确性和充分性。"
  },
  "missing": [
    {
      "item": "间隔期具体时长（如90天或180天）",
      "reason": "实际回答仅提及时隔期要求，未给出常见时长，非必需但gold answer提供了这些细节。",
      "severity": "minor"
    },
    {
      "item": "轻症分组限制说明",
      "reason": "gold answer提到了同组轻症只赔一次的规则，实际回答未涉及。",
      "severity": "minor"
    },
    {
      "item": "赔付后保额变化提示",
      "reason": "gold answer说明了部分产品轻症赔付后重疾保额不变或减少，实际回答未提及。",
      "severity": "minor"
    }
  ],
  "wrong": [],
  "extra": [],
  "evidence": [
    {
      "reference": "actual_answer",
      "text": "轻症赔付次数和金额取决于具体保险合同。一般情况下，轻症可以赔付多次，每次赔付金额通常为基本保险金额的20%至30%，且可能有次数上限（如3次或5次）和间隔期要求。建议查阅您的保险合同条款获取准确信息。"
    }
  ],
  "reasoning_summary": "实际回答准确回应了用户的全部核心疑问：确认了轻症可多次赔付，给出了赔付比例范围，并提示了次数上限和间隔期，最后引导查阅合同。虽然遗漏了部分gold answer中的细节（如间隔期具体时长、分组限制、保额影响），但这些并不妨碍核心意图的满足，且未引入错误信息。因此整体业务期望均被满足，评估结果为 fulfilled。",
  "needs_human_review": false,
  "scenario": "qa_gold_answer",
  "quality_flags": []
}

